        dateWheelLayout = findViewById(R.id.wheel_picker_date_wheel);

        setCurtainEnabled(true);
        getMonthLabelView().setBackgroundColor(0x1A2B79D7);
        getYearLabelView().setBackgroundColor(0x1A2B79D7);
