            visibleItemCount = 5;
            defaultItemPosition = 0;
            sameWidthEnabled = false;
            maxWidthText = "";
            textAlign = ItemTextAlign.CENTER;
            textColor = 0xFF888888;
            selectedTextColor = 0xFF000000;
            textSize = 15 * scaledDensity;
